sections.example:
const target = 5;       // immutable binding
let count = 0;          // will be reassigned

for (let i = 0; i < 3; i++) {
  count += i;
}
console.log(count);     // 3
console.log(target);    // 5

// const prevents reassignment, not mutation
const arr = [1, 2];
arr.push(3);            // OK — mutating the array
console.log(arr);       // [1, 2, 3]

