sections.example:
// Loose vs strict equality
console.log(1 == "1");    // true (coercion)
console.log(1 === "1");   // false (no coercion)

// + concatenates with strings
console.log(5 + "3");     // "53"
console.log(5 - "3");     // 2 (converts to number)

// Explicit conversion
const num = Number("42"); // 42
const str = String(100);  // "100"

